import java.util.*;

public class Solution {
    public static long solve(long[][] grid, long k) {
        int m = grid.length;
        int n = grid[0].length;
        int tk = (int) k;
        long[][][] dp = new long[m][n][tk + 1];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                Arrays.fill(dp[i][j], Long.MAX_VALUE);
            }
        }

        PriorityQueue<long[]> queue = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        dp[0][0][0] = 0;
        queue.add(new long[]{0, 0, 0, 0});

        while (!queue.isEmpty()) {
            long[] state = queue.poll();
            long cost = state[0];
            int i = (int) state[1];
            int j = (int) state[2];
            int t = (int) state[3];

            if (cost != dp[i][j][t]) continue;

            if (j + 1 < n) {
                long newCost = cost + grid[i][j + 1];
                if (newCost < dp[i][j + 1][t]) {
                    dp[i][j + 1][t] = newCost;
                    queue.add(new long[]{newCost, i, j + 1, t});
                }
            }
            if (i + 1 < m) {
                long newCost = cost + grid[i + 1][j];
                if (newCost < dp[i + 1][j][t]) {
                    dp[i + 1][j][t] = newCost;
                    queue.add(new long[]{newCost, i + 1, j, t});
                }
            }

            if (t < tk) {
                for (int x = 0; x < m; x++) {
                    for (int y = 0; y < n; y++) {
                        if (grid[x][y] <= grid[i][j]) {
                            if (cost < dp[x][y][t + 1]) {
                                dp[x][y][t + 1] = cost;
                                queue.add(new long[]{cost, x, y, t + 1});
                            }
                        }
                    }
                }
            }
        }

        long ans = Long.MAX_VALUE;
        for (int t = 0; t <= tk; t++) {
            if (dp[m - 1][n - 1][t] < ans) {
                ans = dp[m - 1][n - 1][t];
            }
        }
        return ans;
    }
}
```

