                for (int j = 0; j < n; j++) {
                    dp[t][i][j] = INF;
                }
            }
        }
        dp[0][0][0] = 0;

        for (int t = 0; t <= kInt; t++) {
            if (t >= 1) {
                int maxVal = 0;
                for (int i = 0; i < m; i++) {
                    for (int j = 0; j < n; j++) {
                        if (grid[i][j] > maxVal) {
                            maxVal = (int) grid[i][j];
                        }
                    }
                }
                long[] minValue = new long[maxVal + 2];
                Arrays.fill(minValue, INF);
                for (int i = 0; i < m; i++) {
