                for (int i = 0; i < m; i++) {
                    for (int j = 0; j < n; j++) {
                        int g = (int) grid[i][j];
                        if (minValue[g] < dp[t][i][j]) {
                            dp[t][i][j] = minValue[g];
                        }
                    }
                }
            }

