            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    if (dp[t][i][j] < INF) {
                        pq.add(new long[]{dp[t][i][j], i, j});
                    }
                }
            }

            while (!pq.isEmpty()) {
                long[] cur = pq.poll();
                long cost = cur[0];
                int i = (int) cur[1];
                int j = (int) cur[2];
                if (cost != dp[t][i][j]) continue;
                if (j + 1 < n) {
