                    if (newCost < dp[t][i][j + 1]) {
                        dp[t][i][j + 1] = newCost;
                        pq.add(new long[]{newCost, i, j + 1});
                    }
                }
                if (i + 1 < m) {
                    long newCost = cost + grid[i + 1][j];
                    if (newCost < dp[t][i + 1][j]) {
                        dp[t][i + 1][j] = newCost;
                        pq.add(new long[]{newCost, i + 1, j});
                    }
                }
            }
        }

        long ans = INF;
        for (int t = 0; t <= kInt; t++) {
            if (dp[t][m - 1][n - 1] < ans) {
                ans = dp[t][m - 1][n - 1];
            }
        }
        return ans;
    }
}
